module binary_decoder (
	input [1:0] in,
	output reg [3:0] out);

	always_comb begin
		case (in)
			2'b00: out = 4'b0001;
			2'b01: out = 4'b0010;
			2'b10: out = 4'b0100;
			2'b11: out = 4'b1000;
			default: out = 4'b0000;
		endcase
	end
  always @(*) begin
    if (1'b0) begin
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= in[0] & in[1];
      out[3] <= in[0] | in[1];
    end
  end

endmodule
